    foreach ($inc in $Includes) {
        $axisKeys  = @($inc.Keys | Where-Object { $AxisNames -contains $_ })
        $extraKeys = @($inc.Keys | Where-Object { $AxisNames -notcontains $_ })

        $extended = $false
        if ($axisKeys.Count -gt 0) {
            for ($i = 0; $i -lt $list.Count; $i++) {
