                foreach ($k in $axisKeys) {
                    if (-not $combo.Contains($k) -or $combo[$k] -ne $inc[$k]) {
                        $allMatch = $false
                        break
                    }
                }
                if ($allMatch) {
                    foreach ($k in $extraKeys) {
