                    }
                    $extended = $true
                }
            }
        }

        if (-not $extended) {
            # No matching combo (or no axis keys at all) -> add as a new combo.
            $newCombo = [ordered]@{}
            foreach ($k in $inc.Keys) { $newCombo[$k] = $inc[$k] }
